import { Registry } from '../../core/zc-registry';
import { euclideanDistance } from './_point';

export function isCircleWithinCircle(circle1, circle2) {
    let dist = euclideanDistance(circle1, circle2),
        r1 = circle1.r,
        r2 = circle2.r;

    return dist + r2 == r1 || dist + r2 < r1;
}

export function closestToCircle(circle, point) {
    let [cx, cy, r] = circle,
        [x, y] = point,
        distance = euclideanDistance({ x: cx, y: cy }, { x, y }),
        closest;

    if (distance >= r) {
        closest = distance - r;
    } else {
        closest = r - distance;
    }

    return closest;
}

Registry.setComponent('geometryUtils.circle.closestToCircle', closestToCircle);
Registry.setComponent('geometryUtils.circle.isCircleWithinCircle', isCircleWithinCircle);
